mapper.select:
select *
from knowledge_document_structure
where document_id = #{documentId}
  and document_version_id = #{versionId}
  and deleted = 0
order by sort_order asc, id asc

mapper.update:
update knowledge_document_structure
set deleted = 1
where document_id = #{documentId}
  and document_version_id = #{versionId}
  and deleted = 0
